import { useCallback, useEffect, useState } from 'react';
import { useMinLoadingTime } from '@linm-soft/common-components';

/** API `loading` + optional client search pulse (`searchBusy`) → skeleton via `useMinLoadingTime`. */
export function useCatalogTableBusy(loading: boolean) {
  const [searchBusy, setSearchBusy] = useState(false);
  const busy = loading || searchBusy;
  const showTableLoading = useMinLoadingTime(busy);

  const pulseSearch = useCallback((apply: () => void) => {
    setSearchBusy(true);
    apply();
  }, []);

  useEffect(() => {
    if (!searchBusy) return;
    const t = setTimeout(() => setSearchBusy(false), 0);
    return () => clearTimeout(t);
  }, [loading, searchBusy]);

  return { searchBusy, setSearchBusy, showTableLoading, pulseSearch };
}
