import React from 'react';
import { TableCard } from '@linm-soft/common-components';
import { CatalogTableSkeleton } from './CatalogTableSkeleton';
import catalogListStyles from '../../styles/catalogTableCard.module.css';
import styles from '../../styles/erpPage.module.css';

export type CatalogListShellProps = {
  testIdPrefix: string;
  title: string;
  filters: React.ReactNode;
  showTableLoading: boolean;
  footer?: React.ReactNode;
  skeletonRows?: number;
  filtersTestId?: string;
  children: React.ReactNode;
};

export const CatalogListShell: React.FC<CatalogListShellProps> = ({
  testIdPrefix,
  title,
  filters,
  showTableLoading,
  footer,
  skeletonRows = 5,
  filtersTestId,
  children,
}) => (
  <div data-testid={`${testIdPrefix}-table-card`}>
    <TableCard
      header={
        <div className={catalogListStyles.tableHeader}>
          <span className={catalogListStyles.tableTitle}>{title}</span>
          <div
            className={`${styles.filtersBar} ${catalogListStyles.tableFilters}`}
            data-testid={filtersTestId ?? `${testIdPrefix}-filters`}
          >
            {filters}
          </div>
        </div>
      }
      footer={!showTableLoading ? footer : undefined}
    >
      {showTableLoading ? <CatalogTableSkeleton rows={skeletonRows} /> : children}
    </TableCard>
  </div>
);
