import React from 'react';
import styles from './CatalogTableSkeleton.module.css';

export interface CatalogTableSkeletonProps {
  /** Number of placeholder rows — default 5 (QLCV MedicalIncidentTable) */
  rows?: number;
}

/** Shimmer rows inside TableCard body while list loads or client search applies. */
export const CatalogTableSkeleton: React.FC<CatalogTableSkeletonProps> = ({ rows = 5 }) => (
  <div className={styles.loadingRows} data-testid="catalog-table-skeleton" aria-hidden>
    {Array.from({ length: rows }, (_, i) => (
      <div key={i} className={styles.skeletonRow} />
    ))}
  </div>
);
