import { useEffect, useMemo, useState } from 'react';
import { companyService } from '../services/company/companyService';
import { formatCompanyLabel } from '../utils/companyField';

export function useCompanyLabelMap(): {
  labelFor: (companyId?: string) => string;
  sessionCompanyId: string | undefined;
  loading: boolean;
} {
  const [byId, setById] = useState<Record<string, string>>({});
  const [sessionCompanyId, setSessionCompanyId] = useState<string | undefined>();
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      setLoading(true);
      companyService
        .getActiveList()
        .then(list => {
          if (cancelled) return;
          const map: Record<string, string> = {};
          for (const c of list) {
            map[c.id] = c.shortName?.trim() ? `${c.shortName} — ${c.name}` : c.name;
          }
          setById(map);
          if (list.length > 0 && !sessionCompanyId) {
            setSessionCompanyId(list[0].id);
          }
        })
        .catch(() => {
          if (!cancelled) setById({});
        })
        .finally(() => {
          if (!cancelled) setLoading(false);
        });
    }, 0);
    return () => {
      cancelled = true;
      clearTimeout(t);
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const labelFor = useMemo(
    () => (companyId?: string) => {
      if (!companyId) return '—';
      return byId[companyId] ?? formatCompanyLabel(companyId);
    },
    [byId],
  );

  return { labelFor, sessionCompanyId, loading };
}
